1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { createHash } from 'node:crypto';
4	import { Repository } from 'typeorm';
5	import { AuditLogEntity } from './audit-log.entity';
6	import { AuditLogQueryDto } from './dto/audit-log-query.dto';
7	
8	@Injectable()
9	export class AuditService {
10	  constructor(
11	    @InjectRepository(AuditLogEntity)
12	    private readonly auditRepository: Repository<AuditLogEntity>
13	  ) {}
14	
15	  async appendLog(input: {
16	    entityType: string;
17	    entityId?: string | null;
18	    action: string;
19	    actorId?: string | null;
20	    payload?: Record<string, unknown>;
21	  }): Promise<AuditLogEntity> {
22	    const previous = await this.auditRepository
23	      .createQueryBuilder('audit')
24	      .orderBy('audit.created_at', 'DESC')
25	      .addOrderBy('audit.id', 'DESC')
26	      .limit(1)
27	      .getOne();
28	
29	    const payload = input.payload ?? {};
30	    const createdAt = new Date().toISOString();
31	    const hashInput = this.buildHashInput({
32	      previous_hash: previous?.entryHash ?? null,
33	      entity_type: input.entityType,
34	      entity_id: input.entityId ?? null,
35	      action: input.action,
36	      actor_id: input.actorId ?? null,
37	      payload,
38	      created_at: createdAt
39	    });
40	
41	    const entryHash = createHash('sha256').update(hashInput).digest('hex');
42	
43	    const entity = this.auditRepository.create({
44	      entityType: input.entityType,
45	      entityId: input.entityId ?? null,
46	      action: input.action,
47	      actorId: input.actorId ?? null,
48	      previousHash: previous?.entryHash ?? null,
49	      entryHash,
50	      hashInput,
51	      payload
52	    });
53	
54	    return this.auditRepository.save(entity);
55	  }
56	
57	  async verifyIntegrity(input?: {
58	    from?: string;
59	    to?: string;
60	    limit?: number;
61	  }): Promise<{
62	    valid: boolean;
63	    first_invalid_record_id: string | null;
64	    checked_count: number;
65	    from: string | null;
66	    to: string | null;
67	  }> {
68	    const qb = this.auditRepository.createQueryBuilder('audit').where('audit.deleted_at IS NULL');
69	    if (input?.from) {
70	      qb.andWhere('audit.created_at >= :from', { from: input.from });
71	    }
72	    if (input?.to) {
73	      qb.andWhere('audit.created_at <= :to', { to: input.to });
74	    }
75	
76	    qb.orderBy('audit.created_at', 'ASC').addOrderBy('audit.id', 'ASC');
77	    qb.take(input?.limit && input.limit > 0 ? input.limit : 5000);
78	    const rows = await qb.getMany();
79	
80	    let checkedCount = 0;
81	    let previousEntryHash: string | null = null;
82	
83	    for (let i = 0; i < rows.length; i += 1) {
84	      const row = rows[i]!;
85	      checkedCount += 1;
86	
87	      if ((row.previousHash ?? null) !== previousEntryHash) {
88	        return {
89	          valid: false,
90	          first_invalid_record_id: row.id,
91	          checked_count: checkedCount,
92	          from: rows[0]?.createdAt.toISOString() ?? null,
93	          to: rows[rows.length - 1]?.createdAt.toISOString() ?? null
94	        };
95	      }
96	
97	      if (row.hashInput) {
98	        const recomputed = createHash('sha256').update(row.hashInput).digest('hex');
99	        if (recomputed !== row.entryHash) {
100	          return {
101	            valid: false,
102	            first_invalid_record_id: row.id,
103	            checked_count: checkedCount,
104	            from: rows[0]?.createdAt.toISOString() ?? null,
105	            to: rows[rows.length - 1]?.createdAt.toISOString() ?? null
106	          };
107	        }
108	      }
109	
110	      previousEntryHash = row.entryHash;
111	    }
112	
113	    return {
114	      valid: true,
115	      first_invalid_record_id: null,
116	      checked_count: checkedCount,
117	      from: rows[0]?.createdAt.toISOString() ?? input?.from ?? null,
118	      to: rows[rows.length - 1]?.createdAt.toISOString() ?? input?.to ?? null
119	    };
120	  }
121	
122	  async getLogs(query: AuditLogQueryDto): Promise<{
123	    items: AuditLogEntity[];
124	    page: number;
125	    page_size: number;
126	    total: number;
127	  }> {
128	    const qb = this.auditRepository.createQueryBuilder('audit').where('audit.deleted_at IS NULL');
129	
130	    if (query.actor_id) {
131	      qb.andWhere('audit.actor_id = :actorId', { actorId: query.actor_id });
132	    }
133	
134	    if (query.entity_type) {
135	      qb.andWhere('audit.entity_type = :entityType', { entityType: query.entity_type });
136	    }
137	
138	    if (query.from) {
139	      qb.andWhere('audit.created_at >= :from', { from: query.from });
140	    }
141	
142	    if (query.to) {
143	      qb.andWhere('audit.created_at <= :to', { to: query.to });
144	    }
145	
146	    const page = query.page;
147	    const pageSize = query.page_size;
148	    qb.orderBy('audit.created_at', 'DESC').addOrderBy('audit.id', 'DESC').skip((page - 1) * pageSize).take(pageSize);
149	
150	    const [items, total] = await qb.getManyAndCount();
151	
152	    return {
153	      items,
154	      page,
155	      page_size: pageSize,
156	      total
157	    };
158	  }
159	
160	  private buildHashInput(input: {
161	    previous_hash: string | null;
162	    entity_type: string;
163	    entity_id: string | null;
164	    action: string;
165	    actor_id: string | null;
166	    payload: Record<string, unknown>;
167	    created_at: string;
168	  }): string {
169	    return this.stableStringify(input);
170	  }
171	
172	  private stableStringify(value: unknown): string {
173	    return JSON.stringify(this.sortDeep(value));
174	  }
175	
176	  private sortDeep(value: unknown): unknown {
177	    if (Array.isArray(value)) {
178	      return value.map((item) => this.sortDeep(item));
179	    }
180	
181	    if (value && typeof value === 'object') {
182	      const sorted: Record<string, unknown> = {};
183	      const keys = Object.keys(value as Record<string, unknown>).sort((a, b) => a.localeCompare(b));
184	      for (const key of keys) {
185	        sorted[key] = this.sortDeep((value as Record<string, unknown>)[key]);
186	      }
187	      return sorted;
188	    }
189	
190	    return value;
191	  }
192	}
