1	import { Injectable, Logger, OnModuleDestroy, OnModuleInit } from '@nestjs/common';
2	import { ConfigService } from '@nestjs/config';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { IsNull, Repository } from 'typeorm';
5	import { AuditService } from '../audit/audit.service';
6	import { NotificationEntity } from '../communication/entities/notification.entity';
7	import { WorkflowRequestEntity, WorkflowRequestStatus } from './entities/workflow-request.entity';
8	
9	@Injectable()
10	export class WorkflowReminderService implements OnModuleInit, OnModuleDestroy {
11	  private timer: NodeJS.Timeout | null = null;
12	  private readonly logger = new Logger(WorkflowReminderService.name);
13	
14	  constructor(
15	    private readonly configService: ConfigService,
16	    @InjectRepository(WorkflowRequestEntity)
17	    private readonly requestRepository: Repository<WorkflowRequestEntity>,
18	    @InjectRepository(NotificationEntity)
19	    private readonly notificationRepository: Repository<NotificationEntity>,
20	    private readonly auditService: AuditService
21	  ) {}
22	
23	  onModuleInit(): void {
24	    this.timer = setInterval(() => {
25	      this.sendSlaReminders().catch((error: unknown) => {
26	        const now = new Date();
27	        const leadHoursRaw = this.configService.get<number>('WORKFLOW_REMINDER_LEAD_HOURS') ?? 2;
28	        const leadHours = Number.isFinite(leadHoursRaw) && leadHoursRaw > 0 ? leadHoursRaw : 2;
29	        const windowEnd = new Date(now.getTime() + leadHours * 60 * 60 * 1000);
30	        const details = this.toErrorDetails(error);
31	
32	        this.logger.error(
33	          JSON.stringify({
34	            event: 'workflow_reminder_job_failed',
35	            job: 'workflow_sla_reminder',
36	            run_at: now.toISOString(),
37	            window_end: windowEnd.toISOString(),
38	            error_message: details.message,
39	            error_code: details.code
40	          })
41	        );
42	      });
43	    }, 60 * 1000);
44	  }
45	
46	  onModuleDestroy(): void {
47	    if (this.timer) {
48	      clearInterval(this.timer);
49	      this.timer = null;
50	    }
51	  }
52	
53	  async sendSlaReminders(): Promise<void> {
54	    const now = new Date();
55	    const leadHoursRaw = this.configService.get<number>('WORKFLOW_REMINDER_LEAD_HOURS') ?? 2;
56	    const leadHours = Number.isFinite(leadHoursRaw) && leadHoursRaw > 0 ? leadHoursRaw : 2;
57	    const leadMs = leadHours * 60 * 60 * 1000;
58	    const windowEnd = new Date(now.getTime() + leadMs);
59	    const cooldownEdge = new Date(now.getTime() - 60 * 60 * 1000);
60	
61	    const pending = await this.requestRepository
62	      .createQueryBuilder('wr')
63	      .where('wr.deleted_at IS NULL')
64	      .andWhere('wr.status = :status', { status: WorkflowRequestStatus.PENDING })
65	      .andWhere('wr.deadline_at > :now', { now: now.toISOString() })
66	      .andWhere('wr.deadline_at <= :windowEnd', { windowEnd: windowEnd.toISOString() })
67	      .andWhere('(wr.last_reminder_at IS NULL OR wr.last_reminder_at < :cooldownEdge)', {
68	        cooldownEdge: cooldownEdge.toISOString()
69	      })
70	      .getMany();
71	
72	    for (const request of pending) {
73	      await this.notificationRepository.save(
74	        this.notificationRepository.create({
75	          userId: request.requestedBy,
76	          type: 'workflow_sla_reminder',
77	          title: 'Workflow SLA deadline approaching',
78	          body: `Workflow request ${request.id} is approaching its SLA deadline.`,
79	          payload: {
80	            request_id: request.id,
81	            deadline_at: request.deadlineAt.toISOString()
82	          },
83	          readAt: null
84	        })
85	      );
86	
87	      request.lastReminderAt = new Date();
88	      request.version += 1;
89	      await this.requestRepository.save(request);
90	
91	      await this.auditService.appendLog({
92	        entityType: 'workflow_request',
93	        entityId: request.id,
94	        action: 'workflow.request.sla_reminder',
95	        actorId: null,
96	        payload: {
97	          requested_by: request.requestedBy,
98	          deadline_at: request.deadlineAt.toISOString()
99	        }
100	      });
101	    }
102	  }
103	
104	  private toErrorDetails(error: unknown): { message: string; code: string } {
105	    if (error instanceof Error) {
106	      const withCode = error as Error & { code?: string };
107	      return {
108	        message: withCode.message,
109	        code: typeof withCode.code === 'string' && withCode.code.length > 0 ? withCode.code : 'UNKNOWN'
110	      };
111	    }
112	
113	    if (typeof error === 'string' && error.length > 0) {
114	      return { message: error, code: 'UNKNOWN' };
115	    }
116	
117	    return { message: 'Unknown reminder failure', code: 'UNKNOWN' };
118	  }
119	}
