1	import { Injectable } from '@nestjs/common';
2	import { ConfigService } from '@nestjs/config';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { IsNull, Repository } from 'typeorm';
5	import { AppException } from '../../common/exceptions/app.exception';
6	import { AccessControlService } from '../access-control/access-control.service';
7	import { ScopePolicyService } from '../access-control/scope-policy.service';
8	import { AuditService } from '../audit/audit.service';
9	import { ReservationService } from '../reservation/reservation.service';
10	import { TrustRatingService } from '../trust-rating/trust-rating.service';
11	import { CreateNotificationDto } from './dto/create-notification.dto';
12	import { CreateSupportTicketDto } from './dto/create-support-ticket.dto';
13	import { MarkMessagesReadDto } from './dto/mark-messages-read.dto';
14	import { MessageListQueryDto } from './dto/message-list-query.dto';
15	import { NotificationListQueryDto } from './dto/notification-list-query.dto';
16	import { SendMessageDto } from './dto/send-message.dto';
17	import { SupportTicketListQueryDto } from './dto/support-ticket-list-query.dto';
18	import { MessageEntity } from './entities/message.entity';
19	import { MessageReadEntity } from './entities/message-read.entity';
20	import { NotificationEntity } from './entities/notification.entity';
21	import { SensitiveWordEntity } from './entities/sensitive-word.entity';
22	import { SupportTicketEntity } from './entities/support-ticket.entity';
23	
24	const CHAT_RATE_LIMIT_PER_MINUTE = 20;
25	const SUPPORT_TICKET_STATUS_OPEN = 'OPEN';
26	const SUPPORT_TICKET_STATUS_ESCALATED = 'ESCALATED';
27	const SUPPORT_TICKET_STATUS_RESOLVED = 'RESOLVED';
28	const SUPPORT_TICKET_STATUS_CLOSED = 'CLOSED';
29	
30	@Injectable()
31	export class CommunicationService {
32	  constructor(
33	    private readonly configService: ConfigService,
34	    private readonly reservationService: ReservationService,
35	    private readonly accessControlService: AccessControlService,
36	    private readonly scopePolicyService: ScopePolicyService,
37	    private readonly trustRatingService: TrustRatingService,
38	    private readonly auditService: AuditService,
39	    @InjectRepository(MessageEntity)
40	    private readonly messageRepository: Repository<MessageEntity>,
41	    @InjectRepository(MessageReadEntity)
42	    private readonly messageReadRepository: Repository<MessageReadEntity>,
43	    @InjectRepository(SupportTicketEntity)
44	    private readonly supportTicketRepository: Repository<SupportTicketEntity>,
45	    @InjectRepository(NotificationEntity)
46	    private readonly notificationRepository: Repository<NotificationEntity>,
47	    @InjectRepository(SensitiveWordEntity)
48	    private readonly sensitiveWordRepository: Repository<SensitiveWordEntity>
49	  ) {}
50	
51	  async postMessage(
52	    userId: string,
53	    reservationId: string,
54	    payload: SendMessageDto,
55	    context: { ipAddress?: string | null; deviceId?: string | null }
56	  ): Promise<Record<string, unknown>> {
57	    await this.reservationService.ensureReservationForAttachment(userId, reservationId);
58	    await this.enforceMessageRateLimit(userId);
59	    await this.enforceSensitiveWords(payload.content);
60	
61	    const message = await this.messageRepository.save(
62	      this.messageRepository.create({
63	        reservationId,
64	        senderId: userId,
65	        content: payload.content
66	      })
67	    );
68	
69	    await this.trustRatingService.recordActivitySignal({
70	      userId,
71	      actionType: 'chat_message',
72	      ipAddress: context.ipAddress ?? null,
73	      deviceId: context.deviceId ?? null
74	    });
75	
76	    return this.mapMessage(message);
77	  }
78	
79	  async listMessages(userId: string, reservationId: string, query: MessageListQueryDto): Promise<Record<string, unknown>> {
80	    await this.reservationService.ensureReservationForAttachment(userId, reservationId);
81	
82	    const qb = this.messageRepository.createQueryBuilder('m').where('m.reservation_id = :reservationId', { reservationId });
83	    qb.andWhere('m.deleted_at IS NULL');
84	
85	    if (query.since) {
86	      qb.andWhere('m.created_at >= :since', { since: query.since });
87	    }
88	
89	    qb.orderBy('m.created_at', 'ASC').addOrderBy('m.id', 'ASC');
90	    qb.skip((query.page - 1) * query.page_size).take(query.page_size);
91	
92	    const [items, total] = await qb.getManyAndCount();
93	    return {
94	      items: items.map((item) => this.mapMessage(item)),
95	      page: query.page,
96	      page_size: query.page_size,
97	      total
98	    };
99	  }
100	
101	  async markMessagesRead(userId: string, reservationId: string, payload: MarkMessagesReadDto): Promise<Record<string, unknown>> {
102	    await this.reservationService.ensureReservationForAttachment(userId, reservationId);
103	
104	    if (!payload.last_read_message_id && !payload.last_read_at) {
105	      throw new AppException('CHAT_READ_CURSOR_REQUIRED', 'last_read_message_id or last_read_at is required', {}, 422);
106	    }
107	
108	    if (payload.last_read_message_id) {
109	      const exists = await this.messageRepository.findOne({
110	        where: { id: payload.last_read_message_id, reservationId, deletedAt: IsNull() }
111	      });
112	      if (!exists) {
113	        throw new AppException('NOT_FOUND', 'Message not found', { message_id: payload.last_read_message_id }, 404);
114	      }
115	    }
116	
117	    const existing = await this.messageReadRepository.findOne({ where: { reservationId, userId, deletedAt: IsNull() } });
118	    const entity = existing ?? this.messageReadRepository.create({ reservationId, userId });
119	    entity.lastReadMessageId = payload.last_read_message_id ?? entity.lastReadMessageId ?? null;
120	    entity.lastReadAt = payload.last_read_at ? new Date(payload.last_read_at) : entity.lastReadAt ?? new Date();
121	    const saved = await this.messageReadRepository.save(entity);
122	
123	    return {
124	      reservation_id: saved.reservationId,
125	      user_id: saved.userId,
126	      last_read_message_id: saved.lastReadMessageId,
127	      last_read_at: saved.lastReadAt?.toISOString() ?? null,
128	      version: saved.version
129	    };
130	  }
131	
132	  async createSupportTicket(userId: string, payload: CreateSupportTicketDto): Promise<Record<string, unknown>> {
133	    await this.reservationService.ensureReservationForAttachment(userId, payload.reservation_id);
134	
135	    const ticket = await this.supportTicketRepository.save(
136	      this.supportTicketRepository.create({
137	        reservationId: payload.reservation_id,
138	        ownerUserId: userId,
139	        category: payload.category,
140	        description: payload.description,
141	        messageId: payload.message_id ?? null,
142	        status: SUPPORT_TICKET_STATUS_OPEN
143	      })
144	    );
145	
146	    await this.auditService.appendLog({
147	      entityType: 'support_ticket',
148	      entityId: ticket.id,
149	      action: 'support.ticket.create',
150	      actorId: userId,
151	      payload: {
152	        reservation_id: payload.reservation_id,
153	        category: payload.category
154	      }
155	    });
156	
157	    return this.mapSupportTicket(ticket);
158	  }
159	
160	  async escalateSupportTicket(
161	    userId: string,
162	    ticketId: string,
163	    payload: { reason?: string }
164	  ): Promise<Record<string, unknown>> {
165	    const ticket = await this.getSupportTicketOrThrow(ticketId);
166	
167	    const roles = await this.scopePolicyService.getRoles(userId);
168	    const isStaffOrOps = roles.includes('staff') || roles.includes('ops_admin');
169	    const isOwner = ticket.ownerUserId === userId;
170	
171	    if (!isStaffOrOps && !isOwner) {
172	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
173	    }
174	
175	    if (isOwner) {
176	      await this.reservationService.ensureReservationForAttachment(userId, ticket.reservationId);
177	    } else {
178	      await this.reservationService.ensureReservationRecordExists(ticket.reservationId);
179	    }
180	    if (ticket.status !== SUPPORT_TICKET_STATUS_OPEN) {
181	      throw new AppException('SUPPORT_TICKET_INVALID_STATE', 'Ticket cannot be escalated from current state', {}, 422);
182	    }
183	
184	    ticket.status = SUPPORT_TICKET_STATUS_ESCALATED;
185	    ticket.version += 1;
186	    const saved = await this.supportTicketRepository.save(ticket);
187	
188	    await this.auditService.appendLog({
189	      entityType: 'support_ticket',
190	      entityId: saved.id,
191	      action: 'support.ticket.escalate',
192	      actorId: userId,
193	      payload: {
194	        reservation_id: saved.reservationId,
195	        owner_user_id: saved.ownerUserId,
196	        reason: payload.reason ?? null
197	      }
198	    });
199	
200	    await this.notifyTicketOwner(saved.ownerUserId, userId, 'support_ticket_escalated', 'Support ticket escalated', {
201	      ticket_id: saved.id,
202	      reservation_id: saved.reservationId,
203	      reason: payload.reason ?? null
204	    });
205	
206	    return this.mapSupportTicket(saved);
207	  }
208	
209	  async resolveSupportTicket(
210	    userId: string,
211	    ticketId: string,
212	    payload: { resolution_note?: string }
213	  ): Promise<Record<string, unknown>> {
214	    const ticket = await this.getSupportTicketOrThrow(ticketId);
215	
216	    const roles = await this.scopePolicyService.getRoles(userId);
217	    const isStaffOrOps = roles.includes('staff') || roles.includes('ops_admin');
218	    if (!isStaffOrOps) {
219	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
220	    }
221	
222	    await this.reservationService.ensureReservationRecordExists(ticket.reservationId);
223	
224	    const validSourceStatuses = new Set([SUPPORT_TICKET_STATUS_OPEN, SUPPORT_TICKET_STATUS_ESCALATED]);
225	    if (!validSourceStatuses.has(ticket.status)) {
226	      throw new AppException('SUPPORT_TICKET_INVALID_STATE', 'Ticket cannot be resolved from current state', {}, 422);
227	    }
228	
229	    const previousStatus = ticket.status;
230	    ticket.status = SUPPORT_TICKET_STATUS_RESOLVED;
231	    ticket.version += 1;
232	    const saved = await this.supportTicketRepository.save(ticket);
233	
234	    await this.auditService.appendLog({
235	      entityType: 'support_ticket',
236	      entityId: saved.id,
237	      action: 'support.ticket.resolve',
238	      actorId: userId,
239	      payload: {
240	        reservation_id: saved.reservationId,
241	        previous_status: previousStatus,
242	        resolution_note: payload.resolution_note ?? null
243	      }
244	    });
245	
246	    await this.notifyTicketOwner(saved.ownerUserId, userId, 'support_ticket_resolved', 'Support ticket resolved', {
247	      ticket_id: saved.id,
248	      reservation_id: saved.reservationId,
249	      resolution_note: payload.resolution_note ?? null,
250	      previous_status: previousStatus
251	    });
252	
253	    return this.mapSupportTicket(saved);
254	  }
