59	  async getFunnelAggregation(userId: string, query: FunnelQueryDto): Promise<Record<string, unknown>> {
60	    await this.requireAnalyticsRead(userId);
61	
62	    const qb = this.eventRepository.createQueryBuilder('e').where('e.deleted_at IS NULL');
63	    qb.andWhere('e.occurred_at >= :from', { from: query.from });
64	    qb.andWhere('e.occurred_at <= :to', { to: query.to });
65	    qb.andWhere('e.event_type IN (:...eventTypes)', {
66	      eventTypes: ['impression', 'click', 'read_completion', 'conversion']
67	    });
68	    if (query.subject_type) {
69	      qb.andWhere('e.subject_type = :subjectType', { subjectType: query.subject_type });
70	    }
71	
72	    const rows = await qb
73	      .select('e.event_type', 'event_type')
74	      .addSelect('COUNT(e.id)', 'count')
75	      .groupBy('e.event_type')
76	      .getRawMany<{ event_type: string; count: string }>();
77	
78	    const stageOrder = ['impression', 'click', 'read_completion', 'conversion'];
79	    const stageCounts = stageOrder.map((stage) => ({
80	      stage,
81	      count: Number(rows.find((row) => row.event_type === stage)?.count ?? 0)
82	    }));
83	
84	    const firstCount = stageCounts[0].count;
85	    const conversionRate = firstCount > 0 ? Number(((stageCounts[3].count / firstCount) * 100).toFixed(2)) : 0;
86	
87	    return {
88	      from: query.from,
89	      to: query.to,
90	      stages: stageCounts,
91	      conversion_rate_percent: conversionRate
92	    };
93	  }
