411	  private async buildCsv(reportType: string, filters: Record<string, unknown>, columns: string[]): Promise<string> {
412	    if (reportType === 'funnel') {
413	      const from = String(filters.from ?? new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString());
414	      const to = String(filters.to ?? new Date().toISOString());
415	      const funnel = await this.getFunnelAggregation('system', { from, to, subject_type: filters.subject_type as string | undefined });
416	
417	      const headers = columns.length > 0 ? columns : ['stage', 'count'];
418	      const rows = (funnel.stages as Array<{ stage: string; count: number }>).map((stage) => [stage.stage, String(stage.count)]);
419	      return [headers.join(','), ...rows.map((row) => row.join(','))].join('\n');
420	    }
421	
422	    if (reportType === 'content_quality') {
423	      const from = String(filters.from ?? new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString());
424	      const to = String(filters.to ?? new Date().toISOString());
425	      const cq = await this.getContentQualityAggregation('system', {
426	        from,
427	        to,
428	        subject_type: filters.subject_type as string | undefined
429	      });
430	
431	      const rows: string[][] = [
432	        ['impression_count', String(cq.impression_count)],
433	        ['completion_count', String((cq.completion_metric as { completion_count: number }).completion_count)],
434	        ['completion_rate_percent', String((cq.completion_metric as { completion_rate_percent: number }).completion_rate_percent)],
435	        ['engagement_count', String((cq.engagement_metric as { engagement_count: number }).engagement_count)],
436	        ['engagement_rate_percent', String((cq.engagement_metric as { engagement_rate_percent: number }).engagement_rate_percent)],
437	        ['share_count', String((cq.share_metric as { share_count: number }).share_count)],
438	        ['share_rate_percent', String((cq.share_metric as { share_rate_percent: number }).share_rate_percent)]
439	      ];
440	      const headers = columns.length > 0 ? columns : ['metric', 'value'];
441	      return [headers.join(','), ...rows.map((row) => row.join(','))].join('\n');
442	    }
443	
444	    if (reportType === 'retention') {
445	      const cohort_start = String(filters.cohort_start ?? new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString());
446	      const cohort_end = String(filters.cohort_end ?? new Date().toISOString());
447	      const bucket = filters.bucket ? String(filters.bucket) : undefined;
448	      const retention = await this.getRetentionAggregation('system', { cohort_start, cohort_end, bucket });
449	
450	      const headers = columns.length > 0 ? columns : [
451	        'cohort_start',
452	        'cohort_end',
453	        'bucket',
454	        'cohort_size',
455	        'retained_size',
456	        'retention_rate_percent'
457	      ];
458	
459	      const row = [
460	        String(retention.cohort_start),
461	        String(retention.cohort_end),
462	        String(retention.bucket),
463	        String(retention.cohort_size),
464	        String(retention.retained_size),
465	        String(retention.retention_rate_percent)
466	      ];
467	
468	      return [headers.join(','), row.join(',')].join('\n');
469	    }
470	
471	    throw new AppException(
472	      'ANALYTICS_REPORT_TYPE_NOT_SUPPORTED',
473	      `Unsupported report_type. Supported values: ${ANALYTICS_CSV_REPORT_TYPES.join(', ')}`,
474	      { report_type: reportType },
475	      422
476	    );
477	  }
