13	@Injectable()
14	export class PermissionsGuard implements CanActivate {
15	  constructor(
16	    private readonly reflector: Reflector,
17	    private readonly accessControlService: AccessControlService
18	  ) {}
19	
20	  async canActivate(context: ExecutionContext): Promise<boolean> {
21	    const requiredPermissions = this.reflector.getAllAndOverride<string[]>(PERMISSIONS_KEY, [
22	      context.getHandler(),
23	      context.getClass()
24	    ]);
25	
26	    if (!requiredPermissions || requiredPermissions.length === 0) {
27	      return true;
28	    }
29	
30	    const request = context.switchToHttp().getRequest<RequestWithContext>();
31	    const userId = request.user?.userId;
