1	export const API_BASE_PATH = import.meta.env.VITE_API_BASE_PATH ?? '/api/v1'
2	
3	export type ApiErrorDetail = {
4	  field: string
5	  rule: string
6	  message: string
7	}
8	
9	export type ApiErrorEnvelope = {
10	  error: {
11	    code: string
12	    message: string
13	    details: ApiErrorDetail[]
14	  }
15	  request_id: string
16	}
17	
18	export class ApiClientError extends Error {
19	  status: number
20	  code: string
21	  details: ApiErrorDetail[]
22	  requestId: string
23	
24	  constructor(status: number, envelope: ApiErrorEnvelope) {
25	    super(envelope.error.message)
26	    this.name = 'ApiClientError'
27	    this.status = status
28	    this.code = envelope.error.code
29	    this.details = envelope.error.details
30	    this.requestId = envelope.request_id
31	  }
32	}
33	
34	type HttpMethod = 'GET' | 'POST' | 'PATCH' | 'PUT' | 'DELETE'
35	
36	type RequestOptions<TBody> = {
37	  method?: HttpMethod
38	  body?: TBody
39	  csrfToken?: string
40	  signal?: AbortSignal
41	  authMode?: 'token' | 'cookie'
42	  /** Override fetch credentials; use `omit` for login so no session cookie is sent (avoids CSRF without X-CSRF-TOKEN). */
43	  credentials?: RequestCredentials
44	}
45	
46	type ApiListener = (error: ApiClientError) => void
47	
48	let authToken = ''
49	const listeners = new Set<ApiListener>()
50	
51	export function setAuthToken(token: string): void {
52	  authToken = token
53	}
54	
55	export function subscribeApiErrors(listener: ApiListener): () => void {
56	  listeners.add(listener)
57	  return () => listeners.delete(listener)
58	}
59	
60	function notifyApiError(error: ApiClientError): void {
61	  listeners.forEach((listener) => listener(error))
62	}
63	
64	export async function apiRequest<TResponse, TBody = unknown>(
65	  path: string,
66	  options: RequestOptions<TBody> = {},
67	): Promise<TResponse> {
68	  const method = options.method ?? 'GET'
69	  const requestId = crypto.randomUUID()
70	
71	  const headers: Record<string, string> = {
72	    Accept: 'application/json',
73	    'X-Request-Id': requestId,
74	    'X-Workstation-Id': 'ws-frontdesk-01',
75	  }
76	
77	  if (options.authMode === 'cookie') {
78	    headers['X-Auth-Mode'] = 'cookie'
79	  }
80	
81	  if (authToken !== '') {
82	    headers.Authorization = `Bearer ${authToken}`
83	  }
84	
85	  if (options.csrfToken) {
86	    headers['X-CSRF-TOKEN'] = options.csrfToken
87	  }
88	
89	  const init: RequestInit = {
90	    method,
91	    headers,
92	    credentials:
93	      options.credentials ??
94	      (options.authMode === 'cookie' ? 'include' : 'same-origin'),
95	    signal: options.signal,
96	  }
97	
98	  if (options.body !== undefined) {
99	    headers['Content-Type'] = 'application/json'
100	    init.body = JSON.stringify(options.body)
101	  }
102	
103	  const response = await fetch(`${API_BASE_PATH}${path}`, init)
104	
105	  if (response.status === 204) {
106	    return undefined as TResponse
107	  }
108	
109	  const payload = (await response.json()) as TResponse | ApiErrorEnvelope
110	
111	  if (!response.ok) {
112	    const envelope = payload as ApiErrorEnvelope
113	    const error = new ApiClientError(response.status, envelope)
114	    notifyApiError(error)
115	    throw error
116	  }
117	
118	  return payload as TResponse
119	}
120	
121	export function toActionableMessage(error: unknown): string {
122	  if (!(error instanceof ApiClientError)) {
123	    return 'Unexpected client error. Please retry the action.'
124	  }
125	
126	  if (error.code === 'SESSION_EXPIRED') {
127	    return 'Your session expired due to inactivity. Please sign in again.'
128	  }
129	
130	  if (error.code === 'CAPTCHA_REQUIRED') {
131	    return 'Please complete CAPTCHA verification before signing in.'
132	  }
133	
134	  if (error.code === 'FORBIDDEN') {
135	    return 'You do not have permission to perform this action.'
136	  }
137	
138	  if (error.details.length > 0) {
139	    return `${error.message} (${error.details[0].message})`
140	  }
141	
142	  return error.message
143	}
