import { useAuthStore } from '../stores/auth'

const INACTIVITY_EVENTS = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'] as const

export function useInactivityTimeout(timeoutMs = 15 * 60 * 1000) {
  const authStore = useAuthStore()
  let timerId: ReturnType<typeof setTimeout> | null = null

  function resetTimer() {
    if (timerId !== null) clearTimeout(timerId)
    timerId = setTimeout(() => {
      authStore.markSessionExpired()
    }, timeoutMs)
  }

  onMounted(() => {
    INACTIVITY_EVENTS.forEach((event) => window.addEventListener(event, resetTimer))
    resetTimer()
  })

  onUnmounted(() => {
    INACTIVITY_EVENTS.forEach((event) => window.removeEventListener(event, resetTimer))
    if (timerId !== null) clearTimeout(timerId)
  })
}
"}

