5	import { randomUUID } from 'node:crypto';
6	import { json, urlencoded, type Request, type Response } from 'express';
7	import { AppModule } from './app.module';
8	
9	async function bootstrap(): Promise<void> {
10	  // Disable Nest's default body-parser (small default limit) so large JSON and multipart uploads are not rejected with 413 before multer runs.
11	  const app = await NestFactory.create<NestExpressApplication>(AppModule, {
12	    bufferLogs: true,
13	    bodyParser: false
14	  });
15	  const bootstrapLogger = new Logger('[http] Bootstrap');
16	  app.useLogger(bootstrapLogger);
17	
18	  app.use(json({ limit: '25mb' }));
19	  app.use(urlencoded({ limit: '25mb', extended: true }));
20	
21	  app.use((req: { requestId?: string }, res: { setHeader: (name: string, value: string) => void }, next: () => void) => {
22	    const requestId = randomUUID();
23	    req.requestId = requestId;
24	    res.setHeader('x-request-id', requestId);
25	    next();
26	  });
27	
28	  const apiPrefix = process.env.API_PREFIX ?? 'api/v1';
29	  const normalizedPrefix = apiPrefix.startsWith('/') ? apiPrefix : `/${apiPrefix}`;
30	  app.setGlobalPrefix(apiPrefix);
31	
32	  app.useGlobalPipes(
33	    new ValidationPipe({
34	      transform: true,
35	      whitelist: true,
36	      forbidNonWhitelisted: true,
37	      transformOptions: { enableImplicitConversion: true }
38	    })
39	  );
40	
41	  const swaggerConfig = new DocumentBuilder()
42	    .setTitle('CareReserve API')
43	    .setDescription(
44	      'CareReserve modular monolith API. Complements docs/api-spec.md. Try it out uses this host; route paths already include the configured API prefix.'
