28	  async createReservation(userId: string, payload: CreateReservationDto): Promise<Record<string, unknown>> {
29	    const roles = await this.scopePolicyService.getRoles(userId);
30	    const isPatient = roles.includes('patient');
31	    const isStaff = roles.includes('staff');
32	    const isOpsAdmin = roles.includes('ops_admin');
33	
34	    if (!isPatient && !isStaff && !isOpsAdmin) {
35	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
36	    }
37	
38	    const mayAssignOtherPatient = isStaff || isOpsAdmin;
39	    if (isPatient && !mayAssignOtherPatient) {
40	      if (payload.patient_id !== undefined && payload.patient_id !== userId) {
41	        throw new AppException(
42	          'RESERVATION_PATIENT_SELF_ONLY',
43	          'Patients may only create reservations for themselves',
44	          { patient_id: payload.patient_id },
45	          403
46	        );
47	      }
48	    }
49	
50	    const patientId = payload.patient_id ?? (isPatient ? userId : null);
51	    if (!patientId) {
52	      throw new AppException('RESERVATION_PATIENT_ID_REQUIRED', 'patient_id is required for non-patient callers', {}, 422);
53	    }
54	
55	    const startTime = new Date(payload.start_time);
56	    const endTime = new Date(payload.end_time);
57	    if (Number.isNaN(startTime.getTime()) || Number.isNaN(endTime.getTime()) || endTime <= startTime) {
58	      throw new AppException('RESERVATION_INVALID_TIME_WINDOW', 'Invalid reservation time window', {}, 422);
59	    }
60	
61	    const reservation = await this.reservationRepository.save(
62	      this.reservationRepository.create({
63	        patientId,
64	        providerId: payload.provider_id ?? null,
65	        startTime,
66	        endTime,
67	        status: ReservationStatus.CREATED,
68	        version: 1
69	      })
70	    );
71	
72	    await this.scopePolicyService.ensureDefaultClinicReservationScope(reservation.id);
73	    await this.scopePolicyService.assignReservationDefaultScopeFromActor(userId, reservation.id, roles);
74	
75	    if (payload.notes) {
76	      await this.noteRepository.save(
77	        this.noteRepository.create({
78	          reservationId: reservation.id,
79	          authorId: userId,
80	          note: payload.notes
81	        })
82	      );
83	    }
84	
85	    await this.appendTransition(reservation.id, null, ReservationStatus.CREATED, 'CREATE', userId, null, {
86	      start_time: reservation.startTime?.toISOString(),
87	      end_time: reservation.endTime?.toISOString()
88	    });
89	
90	    return this.toReservationResponse(reservation);
91	  }
