93	  /**
94	   * GET /reservations — role- and scope-constrained (docs/api-spec.md §5).
95	   *
96	   * - patient: only rows where patient_id = caller (self-scope).
97	   * - staff: full clinic operational list; optional query filters apply.
98	   * - ops_admin: same as staff — full list with filters for admin operations.
99	   * - provider: only rows where provider_id = caller; if also patient, (patient_id = caller OR provider_id = caller).
100	   * - merchant: no merchant_id on reservations schema → list forbidden (403).
101	   * - analytics_viewer: this route is not an analytics reporting API → list forbidden unless caller also has patient/staff/provider/ops_admin.
102	   */
103	  async listReservations(userId: string, query: ReservationListQueryDto): Promise<Record<string, unknown>> {
104	    const roles = await this.scopePolicyService.getRoles(userId);
105	    const hasOpsAdmin = roles.includes('ops_admin');
106	    const hasStaff = roles.includes('staff');
107	    const hasProvider = roles.includes('provider');
108	    const hasPatient = roles.includes('patient');
109	    const hasMerchant = roles.includes('merchant');
110	    const hasAnalyticsViewer = roles.includes('analytics_viewer');
111	
112	    const mayListClinicWide = hasOpsAdmin || hasStaff;
113	    const mayListAsProvider = hasProvider;
114	    const mayListAsPatient = hasPatient;
115	
116	    if (hasMerchant && !mayListClinicWide && !mayListAsProvider && !mayListAsPatient) {
117	      throw new AppException(
118	        'RESERVATION_LIST_FORBIDDEN',
119	        'Listing reservations is not permitted for this role',
120	        {},
121	        403
122	      );
123	    }
124	
125	    if (
126	      hasAnalyticsViewer &&
127	      !hasOpsAdmin &&
128	      !hasStaff &&
129	      !hasProvider &&
130	      !hasPatient
131	    ) {
132	      throw new AppException(
133	        'RESERVATION_LIST_FORBIDDEN',
134	        'Listing reservations is not permitted for this role',
135	        {},
136	        403
137	      );
138	    }
139	
140	    if (!mayListClinicWide && !mayListAsProvider && !mayListAsPatient) {
141	      throw new AppException(
142	        'RESERVATION_LIST_FORBIDDEN',
143	        'Listing reservations is not permitted for this role',
144	        {},
145	        403
146	      );
147	    }
148	
149	    const qb = this.reservationRepository.createQueryBuilder('r').where('r.deleted_at IS NULL');
150	
151	    await this.scopePolicyService.applyReservationScopeQuery(qb, userId, roles);
152	
153	    if (query.status) {
154	      qb.andWhere('r.status = :status', { status: query.status });
155	    }
156	    if (query.patient_id) {
157	      qb.andWhere('r.patient_id = :patientId', { patientId: query.patient_id });
158	    }
159	    if (query.provider_id) {
160	      qb.andWhere('r.provider_id = :providerId', { providerId: query.provider_id });
161	    }
162	    if (query.from) {
163	      qb.andWhere('r.start_time >= :from', { from: query.from });
164	    }
165	    if (query.to) {
166	      qb.andWhere('r.start_time <= :to', { to: query.to });
167	    }
168	
169	    const sortable = new Set(['created_at', 'updated_at', 'start_time', 'status']);
170	    const sortBy = sortable.has(query.sort_by ?? '') ? query.sort_by ?? 'created_at' : 'created_at';
171	    const sortOrder = query.sort_order === 'asc' ? 'ASC' : 'DESC';
172	    qb.orderBy(`r.${sortBy}`, sortOrder as 'ASC' | 'DESC').addOrderBy('r.id', 'DESC');
173	
174	    qb.skip((query.page - 1) * query.page_size).take(query.page_size);
175	    const [items, total] = await qb.getManyAndCount();
176	
177	    return {
178	      items: items.map((reservation) => this.toReservationResponse(reservation)),
179	      page: query.page,
180	      page_size: query.page_size,
181	      total
182	    };
183	  }
