35	  async createDefinition(userId: string, payload: CreateWorkflowDefinitionDto): Promise<Record<string, unknown>> {
36	    await this.requireOpsAdmin(userId);
37	
38	    const sortedSteps = [...payload.steps].sort((a, b) => a.order - b.order || a.approver_role.localeCompare(b.approver_role));
39	    if (payload.approval_mode === WorkflowApprovalMode.ANY_ONE) {
40	      for (let i = 1; i < sortedSteps.length; i += 1) {
41	        if (sortedSteps[i].order === sortedSteps[i - 1].order) {
42	          throw new AppException(
43	            'WORKFLOW_DUPLICATE_STEP_ORDER',
44	            'Duplicate step order is not allowed for ANY_ONE workflows',
45	            {},
46	            422
47	          );
48	        }
49	      }
50	    }
51	
52	    const queryRunner = this.dataSource.createQueryRunner();
53	    await queryRunner.connect();
54	    await queryRunner.startTransaction();
55	
56	    try {
57	      const definition = await queryRunner.manager.save(
58	        WorkflowDefinitionEntity,
59	        this.definitionRepository.create({
60	          name: payload.name,
61	          approvalMode: payload.approval_mode,
62	          slaHours: payload.sla_hours ?? 48,
63	          active: true,
64	          createdBy: userId
65	        })
66	      );
67	
68	      const steps = sortedSteps.map((step) =>
69	        this.stepRepository.create({
70	          workflowDefinitionId: definition.id,
71	          order: step.order,
72	          approverRole: step.approver_role,
73	          conditions: step.conditions ?? {}
74	        })
75	      );
76	      const savedSteps = await queryRunner.manager.save(WorkflowStepEntity, steps);
77	
78	      await queryRunner.commitTransaction();
79	
80	      await this.auditService.appendLog({
81	        entityType: 'workflow_definition',
82	        entityId: definition.id,
83	        action: 'workflow.definition.create',
84	        actorId: userId,
85	        payload: {
86	          approval_mode: definition.approvalMode,
87	          sla_hours: definition.slaHours,
88	          steps: savedSteps.length
89	        }
90	      });
91	
92	      return {
93	        workflow_definition_id: definition.id,
94	        name: definition.name,
95	        approval_mode: definition.approvalMode,
96	        sla_hours: definition.slaHours,
97	        steps: savedSteps
98	          .sort((a, b) => a.order - b.order)
99	          .map((step) => ({
100	            step_id: step.id,
101	            order: step.order,
102	            approver_role: step.approverRole,
103	            conditions: step.conditions
104	          })),
105	        version: definition.version
106	      };
107	    } catch (error) {
108	      await queryRunner.rollbackTransaction();
109	      throw error;
110	    } finally {
111	      await queryRunner.release();
112	    }
113	  }
