115	  async submitRequest(userId: string, payload: CreateWorkflowRequestDto): Promise<Record<string, unknown>> {
116	    const roles = await this.accessControlService.getUserRoleNames(userId);
117	    if (!roles.some((role) => ['staff', 'provider', 'ops_admin'].includes(role))) {
118	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
119	    }
120	
121	    const definition = await this.definitionRepository.findOne({
122	      where: { id: payload.workflow_definition_id, active: true, deletedAt: IsNull() }
123	    });
124	    if (!definition) {
125	      throw new AppException('WORKFLOW_DEFINITION_NOT_FOUND', 'Workflow definition not found', {}, 404);
126	    }
127	
128	    const steps = await this.stepRepository.find({
129	      where: { workflowDefinitionId: definition.id, deletedAt: IsNull() },
130	      order: { order: 'ASC' }
131	    });
132	    if (steps.length === 0) {
133	      throw new AppException('WORKFLOW_NO_STEPS', 'Workflow definition has no steps', {}, 422);
134	    }
135	
136	    const matchingSteps = steps.filter((step) => this.matchesConditions(step.conditions, payload.payload));
137	    if (matchingSteps.length === 0) {
138	      throw new AppException('WORKFLOW_NO_MATCHING_STEP', 'No workflow step matches provided payload', {}, 422);
139	    }
140	
141	    const minOrder = Math.min(...matchingSteps.map((s) => s.order));
142	
143	    const request = await this.requestRepository.save(
144	      this.requestRepository.create({
145	        workflowDefinitionId: definition.id,
146	        resourceType: payload.resource_type,
147	        resourceRef: payload.resource_ref,
148	        payload: payload.payload,
149	        status: WorkflowRequestStatus.PENDING,
150	        currentStepOrder: minOrder,
151	        requestedBy: userId,
152	        deadlineAt: this.workflowBusinessTimeService.calculateDeadlineAt(new Date(), definition.slaHours)
153	      })
154	    );
155	
156	    await this.auditService.appendLog({
157	      entityType: 'workflow_request',
158	      entityId: request.id,
159	      action: 'workflow.request.create',
160	      actorId: userId,
161	      payload: {
162	        resource_type: request.resourceType,
163	        resource_ref: request.resourceRef,
164	        current_step_order: request.currentStepOrder
165	      }
166	    });
167	
168	    return this.mapRequest(request, definition.approvalMode);
169	  }
