171	  async approveRequest(userId: string, requestId: string, payload: ApproveWorkflowRequestDto): Promise<Record<string, unknown>> {
172	    const request = await this.getPendingRequestOrThrow(requestId);
173	    const definition = await this.getDefinitionOrThrow(request.workflowDefinitionId);
174	    const currentSteps = await this.getStepGroupAtOrder(definition.id, request.currentStepOrder, request.payload);
175	    if (currentSteps.length === 0) {
176	      throw new AppException('WORKFLOW_STEP_NOT_FOUND', 'Current workflow step group not found', {}, 422);
177	    }
178	
179	    const roles = (await this.accessControlService.getUserRoleNames(userId)).map((r) => r.toLowerCase());
180	    const canApprove = roles.includes('ops_admin') || currentSteps.some((s) => roles.includes(s.approverRole));
181	    if (!canApprove) {
182	      throw new AppException('FORBIDDEN', 'Current approver role is required', {}, 403);
183	    }
184	
185	    const alreadyApproved = await this.approvalRepository.findOne({
186	      where: {
187	        workflowRequestId: request.id,
188	        stepOrder: request.currentStepOrder,
189	        approverUserId: userId,
190	        action: 'APPROVE',
191	        deletedAt: IsNull()
192	      }
193	    });
194	    if (alreadyApproved) {
195	      const reloaded = await this.requestRepository.findOne({ where: { id: request.id, deletedAt: IsNull() } });
196	      return this.mapRequest(reloaded ?? request, definition.approvalMode);
197	    }
198	
199	    await this.approvalRepository.save(
200	      this.approvalRepository.create({
201	        workflowRequestId: request.id,
202	        stepOrder: request.currentStepOrder,
203	        approverUserId: userId,
204	        action: 'APPROVE',
205	        comment: payload.comment ?? null
206	      })
207	    );
208	
209	    const stepApproved = await this.evaluateStepGroupComplete(
210	      request.id,
211	      request.currentStepOrder,
212	      currentSteps,
213	      definition.approvalMode
214	    );
215	    if (stepApproved) {
216	      const nextOrder = await this.getNextDistinctStepOrder(definition.id, request.currentStepOrder, request.payload);
217	      if (nextOrder !== null) {
218	        request.currentStepOrder = nextOrder;
219	        request.version += 1;
220	      } else {
221	        request.status = WorkflowRequestStatus.APPROVED;
222	        request.version += 1;
223	      }
224	      await this.requestRepository.save(request);
225	    }
226	
227	    await this.auditService.appendLog({
228	      entityType: 'workflow_request',
229	      entityId: request.id,
230	      action: 'workflow.request.approve',
231	      actorId: userId,
232	      payload: {
233	        step_order: request.currentStepOrder,
234	        status: request.status
235	      }
236	    });
237	
238	    return this.mapRequest(request, definition.approvalMode);
239	  }
