290	  private matchesConditions(conditions: Record<string, unknown>, payload: Record<string, unknown>): boolean {
291	    const keys = Object.keys(conditions ?? {});
292	    if (keys.length === 0) {
293	      return true;
294	    }
295	
296	    return keys.every((key) => payload[key] === conditions[key]);
297	  }
