299	  private async getDefinitionOrThrow(definitionId: string): Promise<WorkflowDefinitionEntity> {
300	    const definition = await this.definitionRepository.findOne({ where: { id: definitionId, deletedAt: IsNull() } });
301	    if (!definition) {
302	      throw new AppException('WORKFLOW_DEFINITION_NOT_FOUND', 'Workflow definition not found', {}, 404);
303	    }
304	    return definition;
305	  }
306	
307	  private async getPendingRequestOrThrow(requestId: string): Promise<WorkflowRequestEntity> {
308	    const request = await this.requestRepository.findOne({ where: { id: requestId, deletedAt: IsNull() } });
309	    if (!request) {
310	      throw new AppException('WORKFLOW_REQUEST_NOT_FOUND', 'Workflow request not found', {}, 404);
311	    }
312	
313	    if (request.status !== WorkflowRequestStatus.PENDING) {
314	      throw new AppException('WORKFLOW_REQUEST_NOT_PENDING', 'Workflow request is not pending', {}, 422);
315	    }
316	
317	    if (isWorkflowDeadlinePassed(request.deadlineAt)) {
318	      request.status = WorkflowRequestStatus.EXPIRED;
319	      request.version += 1;
320	      await this.requestRepository.save(request);
321	      throw new AppException('WORKFLOW_SLA_EXPIRED', 'Workflow request SLA has expired', {}, 422);
322	    }
323	
324	    return request;
325	  }
