327	  private async getStepGroupAtOrder(
328	    definitionId: string,
329	    stepOrder: number,
330	    payload: Record<string, unknown>
331	  ): Promise<WorkflowStepEntity[]> {
332	    const steps = await this.stepRepository.find({
333	      where: { workflowDefinitionId: definitionId, deletedAt: IsNull() },
334	      order: { order: 'ASC', id: 'ASC' }
335	    });
336	
337	    return steps.filter((candidate) => candidate.order === stepOrder && this.matchesConditions(candidate.conditions, payload));
338	  }
339	
340	  private async getNextDistinctStepOrder(
341	    definitionId: string,
342	    currentStepOrder: number,
343	    payload: Record<string, unknown>
344	  ): Promise<number | null> {
345	    const steps = await this.stepRepository.find({
346	      where: { workflowDefinitionId: definitionId, deletedAt: IsNull() },
347	      order: { order: 'ASC', id: 'ASC' }
348	    });
349	
350	    const matching = steps.filter((step) => this.matchesConditions(step.conditions, payload));
351	    const distinctOrders = [...new Set(matching.map((s) => s.order))].sort((a, b) => a - b);
352	    const idx = distinctOrders.indexOf(currentStepOrder);
353	    if (idx === -1 || idx >= distinctOrders.length - 1) {
354	      return null;
355	    }
356	    return distinctOrders[idx + 1] ?? null;
357	  }
358	
359	  private async evaluateStepGroupComplete(
360	    requestId: string,
361	    stepOrder: number,
362	    slots: WorkflowStepEntity[],
363	    mode: WorkflowApprovalMode
364	  ): Promise<boolean> {
365	    const approvals = await this.approvalRepository.find({
366	      where: {
367	        workflowRequestId: requestId,
368	        stepOrder,
369	        action: 'APPROVE',
370	        deletedAt: IsNull()
371	      }
372	    });
373	
374	    const rows = approvals.map((a) => ({ approverUserId: a.approverUserId }));
375	    const userIds = [...new Set(rows.map((r) => r.approverUserId))];
376	    const rolesByUserId: Record<string, string[]> = {};
377	    for (const uid of userIds) {
378	      rolesByUserId[uid] = (await this.accessControlService.getUserRoleNames(uid)).map((r) => r.toLowerCase());
379	    }
380	
381	    const slotPayload = slots.map((s) => ({ id: s.id, approverRole: s.approverRole }));
382	
383	    if (mode === WorkflowApprovalMode.ANY_ONE) {
384	      return isAnyOneStepSatisfied(slotPayload, rows, rolesByUserId);
385	    }
386	
387	    return isAllRequiredStepSatisfied(slotPayload, rows, rolesByUserId);
388	  }
389	
390	  private mapRequest(request: WorkflowRequestEntity, approvalMode: WorkflowApprovalMode): Record<string, unknown> {
391	    return {
392	      request_id: request.id,
393	      workflow_definition_id: request.workflowDefinitionId,
394	      resource_type: request.resourceType,
395	      resource_ref: request.resourceRef,
396	      payload: request.payload,
397	      status: request.status,
398	      approval_mode: approvalMode,
399	      current_step_order: request.currentStepOrder,
400	      deadline_at: request.deadlineAt.toISOString(),
401	      version: request.version,
402	      updated_at: request.updatedAt.toISOString()
403	    };
404	  }
405	}
