306	  async getAdherenceMetrics(userId: string, query: AdherenceQueryDto): Promise<Record<string, unknown>> {
307	    await this.requireAnyRole(userId, ['provider', 'staff', 'analytics_viewer', 'ops_admin']);
308	    const roles = await this.scopePolicyService.getRoles(userId);
309	    const hasOpsAdmin = roles.includes('ops_admin');
310	    const hasStaff = roles.includes('staff');
311	    const hasProvider = roles.includes('provider');
312	    const hasAnalyticsViewer = roles.includes('analytics_viewer');
313	    const hasPatient = roles.includes('patient');
314	
315	    if (!hasOpsAdmin && !hasStaff && !hasProvider && !hasAnalyticsViewer && !hasPatient) {
316	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
317	    }
318	
319	    const qb = this.outcomeRepository
320	      .createQueryBuilder('o')
321	      .innerJoin(FollowUpTaskEntity, 't', 't.id = o.task_id AND t.deleted_at IS NULL')
322	      .innerJoin(FollowUpPlanEntity, 'p', 'p.id = t.plan_id AND p.deleted_at IS NULL')
323	      .leftJoin(ReservationEntity, 'r', 'r.id = p.reservation_id AND r.deleted_at IS NULL')
324	      .where('o.deleted_at IS NULL');
325	
326	    if (!hasOpsAdmin) {
327	      const scopeClauses: string[] = [];
328	      if (hasPatient) {
329	        scopeClauses.push('p.patient_id = :scopeUserId');
330	      }
331	      if (hasProvider) {
332	        scopeClauses.push('r.provider_id = :scopeUserId');
333	        scopeClauses.push('p.created_by = :scopeUserId');
334	      }
335	      if (hasStaff) {
336	        const scopeIds = await this.scopePolicyService.getUserScopeIds(userId);
337	        if (scopeIds.length > 0) {
338	          scopeClauses.push(
339	            `EXISTS (
340	              SELECT 1
341	              FROM reservation_data_scopes rds
342	              WHERE rds.reservation_id = p.reservation_id
343	                AND rds.deleted_at IS NULL
344	                AND rds.scope_id IN (:...scopeIds)
345	            )`
346	          );
347	          qb.setParameter('scopeIds', scopeIds);
348	        }
349	        scopeClauses.push('p.created_by = :scopeUserId');
350	      }
351	      if (hasAnalyticsViewer) {
352	        scopeClauses.push('p.id IS NOT NULL');
353	      }
354	
355	      if (scopeClauses.length === 0) {
356	        throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
357	      }
358	
359	      qb.andWhere(`(${scopeClauses.join(' OR ')})`, { scopeUserId: userId });
360	    }
361	
362	    if (query.patient_id) {
363	      qb.andWhere('p.patient_id = :patientId', { patientId: query.patient_id });
364	    }
365	
366	    if (query.provider_id) {
367	      qb.andWhere('p.created_by = :providerId', { providerId: query.provider_id });
368	    }
369	
370	    if (query.from) {
371	      qb.andWhere('o.created_at >= :from', { from: query.from });
372	    }
373	
374	    if (query.to) {
375	      qb.andWhere('o.created_at <= :to', { to: query.to });
376	    }
377	
378	    const rows = await qb
379	      .select('o.status', 'status')
380	      .addSelect('COUNT(o.id)', 'count')
381	      .addSelect('AVG(o.adherence_score)', 'avg_adherence')
382	      .groupBy('o.status')
383	      .getRawMany<{ status: FollowUpOutcomeStatus; count: string; avg_adherence: string }>();
384	
385	    const totalOutcomes = rows.reduce((sum, row) => sum + Number(row.count), 0);
386	    const weightedAdherenceSum = rows.reduce((sum, row) => sum + Number(row.count) * Number(row.avg_adherence), 0);
387	
388	    return {
389	      total_outcomes: totalOutcomes,
390	      avg_adherence_score: totalOutcomes > 0 ? Number((weightedAdherenceSum / totalOutcomes).toFixed(2)) : 0,
391	      by_status: rows.map((row) => ({
392	        status: row.status,
393	        count: Number(row.count),
394	        avg_adherence_score: Number(Number(row.avg_adherence).toFixed(2))
395	      }))
396	    };
397	  }
