444	  private async assertPlanAccess(
445	    userId: string,
446	    plan: FollowUpPlanEntity,
447	    roles: string[],
448	    requiresProviderOrStaffMutation: boolean
449	  ): Promise<void> {
450	    const hasOpsAdmin = roles.includes('ops_admin');
451	    if (hasOpsAdmin) {
452	      return;
453	    }
454	
455	    if (requiresProviderOrStaffMutation && !roles.includes('provider') && !roles.includes('staff')) {
456	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
457	    }
458	
459	    if (plan.reservationId) {
460	      const reservation = await this.reservationRepository.findOne({ where: { id: plan.reservationId, deletedAt: IsNull() } });
461	      if (!reservation) {
462	        throw new AppException('FORBIDDEN', 'Plan is out of scope', {}, 403);
463	      }
464	
465	      await this.scopePolicyService.assertReservationInScope(userId, reservation, roles);
466	      return;
467	    }
468	
469	    const isPatientOwner = plan.patientId === userId;
470	    const isCreator = Boolean(plan.createdBy && plan.createdBy === userId);
471	    if (isPatientOwner || isCreator) {
472	      return;
473	    }
474	
475	    throw new AppException('FORBIDDEN', 'Plan is out of scope', {}, 403);
476	  }
