5	/**
6	 * Rule-based refund preview for cancellation (≥24h full, 2–24h half, &lt;2h none).
7	 * Acceptance / maintainability: extracted from ReservationService for clarity and unit testing.
8	 */
9	export function computeReservationRefund(startTime: Date | null, referenceMs: number = Date.now()): RefundComputation {
10	  if (!startTime) {
11	    return { refund_percentage: 0, refund_status: RefundStatus.NONE };
12	  }
13	
14	  const diffMs = startTime.getTime() - referenceMs;
15	  const hours = diffMs / (1000 * 60 * 60);
16	
17	  if (hours >= 24) {
18	    return { refund_percentage: 100, refund_status: RefundStatus.FULL };
19	  }
20	  if (hours >= 2) {
21	    return { refund_percentage: 50, refund_status: RefundStatus.PARTIAL };
22	  }
23	  return { refund_percentage: 0, refund_status: RefundStatus.NONE };
24	}
