1	/**
2	 * Deterministic completion rules for workflow steps (see README — Workflow approval modes).
3	 *
4	 * A "step group" is all workflow_steps rows with the same `order` that match the request payload conditions.
5	 * - ANY_ONE: one valid approval from any eligible approver completes the group.
6	 * - ALL_REQUIRED: each slot in the group (each row, stable-sorted by id) must be satisfied by a distinct
7	 *   approver user. An approver satisfies a slot if they have that slot's approver_role or ops_admin.
8	 */
9	
10	export type WorkflowSlot = { id: string; approverRole: string };
11	
12	export type WorkflowApprovalRow = { approverUserId: string };
13	
14	export function isAnyOneStepSatisfied(
15	  slots: WorkflowSlot[],
16	  approvals: WorkflowApprovalRow[],
17	  rolesByUserId: Record<string, string[]>
18	): boolean {
19	  if (slots.length === 0 || approvals.length === 0) {
20	    return false;
21	  }
22	
23	  return approvals.some((a) => approverCanSatisfyAnySlot(a.approverUserId, slots, rolesByUserId));
24	}
25	
26	export function isAllRequiredStepSatisfied(
27	  slots: WorkflowSlot[],
28	  approvals: WorkflowApprovalRow[],
29	  rolesByUserId: Record<string, string[]>
30	): boolean {
31	  if (slots.length === 0) {
32	    return false;
33	  }
34	
35	  const sortedSlots = [...slots].sort((a, b) => a.id.localeCompare(b.id));
36	  const usedApproverIds = new Set<string>();
37	
38	  for (const slot of sortedSlots) {
39	    const match = approvals.find(
40	      (row) =>
41	        !usedApproverIds.has(row.approverUserId) && approverSatisfiesSlot(row.approverUserId, slot, rolesByUserId)
42	    );
43	    if (!match) {
44	      return false;
45	    }
46	    usedApproverIds.add(match.approverUserId);
47	  }
48	
49	  return true;
50	}
51	
52	function approverCanSatisfyAnySlot(userId: string, slots: WorkflowSlot[], rolesByUserId: Record<string, string[]>): boolean {
53	  return slots.some((slot) => approverSatisfiesSlot(userId, slot, rolesByUserId));
54	}
55	
56	function approverSatisfiesSlot(userId: string, slot: WorkflowSlot, rolesByUserId: Record<string, string[]>): boolean {
57	  const roles = rolesByUserId[userId] ?? [];
58	  return roles.includes('ops_admin') || roles.includes(slot.approverRole);
59	}
